 "meeting_decision_overview": {
  "vendorName": "String",
  "summary": "String",
  "confirmed_decisions": [
   {
    "type": "String",
    "description": "String",
    "value": "String",
    "status": "Confirmed | In Principle | Pending Approval"
   }
  ]
 },
 "key_risks_and_pending_items": [
  {
   "topic": "String",
   "riskOrPending": "String",
   "impact": "String",
   "owner": "String"
  }
 ],
 "follow_up_actions": [
  {
   "owner": "String",
   "action": "String",
   "timeframe": "END_OF_MONTH | NEXT_WEEK | ASAP | PLUS_7_DAYS",
   "status": "Not Started"
  }
 ],
 "email_draft": {
  "subject": "String",
  "recipients": [
   "String"
  ],
  "greeting": "郵件開場白，包含稱呼與感謝參與的簡短問候，不超過 50 字，必須使用中式商業郵件的換行方式。",
  "key_agreements": [
   "String",
   "String"
  ],
  "action_items": [
   {
    "owner": "String",
    "action": "String",
    "target_date": "String"
   }
  ],
  "closing": "String"
 }
}

